content:
{
  "sentences": [
    {
      "text": "我會說一點中文。",
      "pinyin": "Wǒ huì shuō yīdiǎn zhōngwén.",
      "pinyin_numeric": "wo3 hui4 shuo1 yi1dian3 zhong1wen2",
      "translation_en": "I can speak a little Chinese.",
      "translation_ko": "저는 중국어를 조금 할 수 있어요."
    },
    {
      "text": "他不太會寫字，可是很努力練習。",
      "pinyin": "Tā bù tài huì xiě zì, kěshì hěn nǔlì liànxí.",
      "pinyin_numeric": "ta1 bu4 tai4 hui4 xie3 zi4, ke3shi4 hen3 nu3li4 lian4xi2",
      "translation_en": "He isn't very good at writing characters, but he practices very hard.",
      "translation_ko": "그는 글씨를 잘 쓰지 못하지만, 아주 열심히 연습해요."
    },
    {
      "sentence": "你會不會彈鋼琴？",
      "pinyin": "Nǐ huì bù huì tán gāngqín?",
      "pinyin_numeric": "ni3 hui4 bu4 hui4 tan2 gang1qin2",
      "translation_en": "Can you play the piano?",
      "translation_ko": "피아노를 칠 줄 아세요?"
    },
    {
      "text": "我完全不會開車，所以打算去學。",
      "pinyin": "Wǒ wánquán bù huì kāichē, suǒyǐ dǎsuàn qù xué.",
      "pinyin_numeric": "wo3 wan2quan2 bu4 hui4 kai1che1, suo3yi3 da3suan4 qu4 xue2",
      "translation_en": "I can't drive at all, so I plan to learn.",
      "translation_ko": "저는 운전을 전혀 못 해서, 배우려고 해요."
    },
    {
      "text": "她已經會游泳了，而且游得越來越快。",
      "pinyin": "Tā yǐjīng huì yóuyǒng le, érqiě yóu de yuèláiyuè kuài.",
      "pinyin_numeric": "ta1 yi3jing1 hui4 you2yong3 le, er2qie3 you2 de5 yue4lai2yue4 kuai4",
      "translation_en": "She already knows how to swim, and she's swimming faster and faster.",
      "translation_ko": "그녀는 이미 수영을 할 줄 알며, 점점 더 빨리 헤엄쳐요."
    },
    {
      "text": "我們還不太會說中文，可是慢慢學就會進步。",
      "pinyin": "Wǒmen hái bù tài huì shuō zhōngwén, kěshì mànman xué jiù huì jìnbù.",
      "pinyin_numeric": "wo3men5 hai2 bu4 tai4 hui4 shuo1 zhong1wen2, ke3shi4 man4man5 xue2 jiu4 hui4 jin4bu4",
      "translation_en": "We still can't speak Chinese very well, but if we learn slowly, we will improve.",
      "translation_ko": "우리는 아직 중국어를 잘 못 하지만, 천천히 배우면 발전할 거예요."
    },
    {
      "text": "你會不會煮菜？我想學做簡單的菜。",
      "pinyin": "Nǐ huì bù huì zhǔ cài? Wǒ xiǎng xué zuò jiǎndān de cài.",
      "pinyin_numeric": "ni3 hui4 bu4 hui4 zhu3 cai4? wo3 xiang3 xue2 zuo4 jian3dan1 de5 cai4.",
      "translation_en": "Can you cook? I want to learn to make simple dishes.",
      "translation_ko": "요리할 줄 아세요? 저는 간단한 요리를 배우고 싶어요."
    },
    {
      "text": "他會唱歌，也會跳舞，可是不會彈鋼琴。",
      "pinyin": "Tā huì chànggē, yě huì tiàowǔ, kěshì bù huì tán gāngqín.",
      "pinyin_numeric": "ta1 hui4 chang4ge1, ye3 hui4 tiao4wu3, ke3shi4 bu4 hui4 tan2 gang1qin2",
      "translation_en": "He can sing and dance, but he can't play the piano.",
      "translation_ko": "그는 노래도 부르고 춤도 출 수 있지만, 피아노는 칠 줄 몰라요."
    },
    {
      "text": "我已經學中文半年了，現在會聽懂一點簡單的句子。",
      "pinyin": "Wǒ yǐjīng xué zhōngwén bànnián le, xiànzài huì tīngdǒng yīdiǎn jiǎndān de jùzi.",
      "pinyin_numeric": "wo3 yi3jing1 xue2 zhong1wen2 ban4nian2 le, xian4zai4 hui4 ting1dong3 yi1dian3 jian3dan1 de5 ju4zi5",
      "translation_en": "I've been studying Chinese for half a year, and now I can understand some simple sentences.",
      "translation_ko": "저는 중국어를 반 년 동안 배웠는데, 이제 간단한 문장을 조금 알아들을 수 있어요."
    },
    {
      "text": "教別人說中文不太簡單，可是很有意思。",
      "pinyin": "Jiào biérén shuō zhōngwén bù tài jiǎndān, kěshì hěn yǒuyìsi.",
      "pinyin_numeric": "jiao4 bie2ren2 shuo1 zhong1wen2 bu4 tai4 jian3dan1, ke3shi4 hen3 you3yi4si5",
      "translation_en": "Teaching others to speak Chinese isn't very simple, but it's very interesting.",
      "translation_ko": "다른 사람에게 중국어 말하기를 가르치는 것은 쉽지 않지만, 아주 재미있어요."
    }
  ]
}
